PRAGMA user_version = 32;

CREATE TABLE ZWACHATSESSION (
    Z_PK INTEGER PRIMARY KEY,
    ZARCHIVED INTEGER DEFAULT 0,
    ZCONTACTIDENTIFIER TEXT,
    ZPARTNERNAME TEXT,
    ZLASTMESSAGEDATE REAL,
    ZSESSIONTYPE INTEGER DEFAULT 0
);

CREATE TABLE ZWAMESSAGE (
    Z_PK INTEGER PRIMARY KEY,
    ZCHATSESSION INTEGER,
    ZMESSAGEDATE REAL NOT NULL,
    ZTEXT TEXT,
    ZMESSAGETYPE INTEGER DEFAULT 0,
    ZMEDIAITEM INTEGER,
    ZISFROMME INTEGER DEFAULT 0,
    ZFROMJID TEXT,
    ZSTARRED INTEGER DEFAULT 0,
    ZISFORWARDED INTEGER DEFAULT 0,
    ZDELETED INTEGER DEFAULT 0,
    ZSORT REAL
);

CREATE TABLE ZWAMEDIAITEM (
    Z_PK INTEGER PRIMARY KEY,
    ZMESSAGE INTEGER,
    ZMIMETYPE TEXT,
    ZFILESIZE INTEGER DEFAULT 0,
    ZLOCALPATH TEXT,
    ZMEDIAURL TEXT
);

CREATE TABLE ZWACONTACT (
    Z_PK INTEGER PRIMARY KEY,
    ZABUSEIDENTIFIER TEXT,
    ZPHONENUMBER TEXT,
    ZFULLNAME TEXT
);

CREATE TABLE ZWACALLINFO (
    Z_PK INTEGER PRIMARY KEY,
    ZCALLDATE REAL NOT NULL,
    ZDURATION INTEGER DEFAULT 0,
    ZISVIDEOCALL INTEGER DEFAULT 0,
    ZPARTNERCONTACT INTEGER,
    ZCALLTYPE INTEGER DEFAULT 0
);

